      async generateAnonymousSentimentInsights(corporateAccountId) {
        const recentData = await this.getCorporateSentimentTrends(corporateAccountId, 30);
        if (recentData.length === 0) {
          return {
            overallSentiment: 50,
            departmentBreakdown: [],
            riskDepartments: [],
            positivityTrends: []
          };
        }
        const overallSentiment = Math.round(
          recentData.reduce((sum, data) => sum + data.sentimentScore, 0) / recentData.length
        );
        const departmentMap = /* @__PURE__ */ new Map();
        recentData.forEach((data) => {
          if (data.department) {
            if (!departmentMap.has(data.department)) {
              departmentMap.set(data.department, []);
            }
            departmentMap.get(data.department).push(data.sentimentScore);
          }
        });
        const departmentBreakdown = Array.from(departmentMap.entries()).map(([department, scores]) => ({
          department,
          sentimentScore: Math.round(scores.reduce((sum, score) => sum + score, 0) / scores.length)
        }));
        const riskDepartments = departmentBreakdown.filter((dept) => dept.sentimentScore < 40).map((dept) => dept.department);
        const positivityTrends = departmentBreakdown.filter((dept) => dept.sentimentScore > 70).map((dept) => dept.department);
        return {
          overallSentiment,
          departmentBreakdown,
          riskDepartments,
          positivityTrends
        };
      }
