      async getMentorBadgesByUser(mentorId) {
        const allBadges = await db.select().from(mentorBadges).where(eq(mentorBadges.isActive, true));
        const earnedBadges = await db.select().from(mentorBadgeAwards).where(eq(mentorBadgeAwards.mentorId, mentorId));
        const badges = allBadges.map((badge) => {
          const earned = earnedBadges.find((e) => e.badgeId === badge.id);
          return {
            id: badge.id,
            badgeName: badge.badgeName,
            badgeIcon: badge.badgeIcon,
            description: badge.description,
            category: badge.category,
            tier: badge.tier,
            tokenReward: badge.tokenReward,
            earnedAt: earned ? earned.awardedAt : null
          };
        });
        badges.sort((a, b) => {
          if (a.earnedAt && !b.earnedAt) return -1;
          if (!a.earnedAt && b.earnedAt) return 1;
          if (a.earnedAt && b.earnedAt) {
            return b.earnedAt.getTime() - a.earnedAt.getTime();
          }
          const nameA = a.badgeName || "";
          const nameB = b.badgeName || "";
          return nameA.localeCompare(nameB);
        });
        return badges;
      }
