  app2.get("/api/corporate/accounts/:accountId/analytics/export", async (req, res) => {
    try {
      const { accountId } = req.params;
      const { format = "csv", period = "30" } = req.query;
      const days = parseInt(period);
      const [account, analytics, teams, employees, challenges] = await Promise.all([
        storage.getCorporateAccount(accountId),
        storage.getCorporateAnalytics(accountId, days),
        storage.getCorporateTeams(accountId),
        storage.getCorporateEmployees(accountId),
        storage.getCorporateChallenges(accountId)
      ]);
      if (!account) {
        return res.status(404).json({ message: "Corporate account not found" });
      }
      const exportData = {
        companyInfo: {
          companyName: account.companyName,
          domain: account.domain,
          industry: account.industry,
          subscriptionTier: account.subscriptionTier,
          exportDate: (/* @__PURE__ */ new Date()).toISOString(),
          reportPeriod: `Last ${days} days`
        },
        summary: {
          totalEmployees: employees.length,
          activeTeams: teams.filter((t) => t.isActive === 1).length,
          totalChallenges: challenges.length,
          activeChallenges: challenges.filter((c) => c.isActive === 1).length,
          totalChallengeCompletions: challenges.reduce((sum, c) => sum + (c.completionCount || 0), 0)
        },
        analytics,
        teams: teams.map((team) => ({
          teamName: team.teamName,
          teamDescription: team.teamDescription || "N/A",
          isActive: team.isActive
        })),
        challenges: challenges.map((challenge) => ({
          title: challenge.title,
          description: challenge.description || "N/A",
          isActive: challenge.isActive
        }))
      };
      if (format === "csv") {
        let csvContent = `# ${account.companyName} Wellness Analytics Export
`;
        csvContent += `# Generated: ${(/* @__PURE__ */ new Date()).toLocaleString()}
`;
        csvContent += `# Period: ${exportData.companyInfo.reportPeriod}

`;
        csvContent += `## Company Summary
`;
        csvContent += `Metric,Value
`;
        csvContent += `Company Name,${exportData.companyInfo.companyName}
`;
        csvContent += `Industry,${exportData.companyInfo.industry}
`;
        csvContent += `Subscription Tier,${exportData.companyInfo.subscriptionTier}
`;
        csvContent += `Total Employees,${exportData.summary.totalEmployees}
`;
        csvContent += `Active Teams,${exportData.summary.activeTeams}
`;
        csvContent += `Total Challenges,${exportData.summary.totalChallenges}
`;
        csvContent += `Challenge Completions,${exportData.summary.totalChallengeCompletions}

`;
        if (analytics.length > 0) {
          csvContent += `## Daily Analytics
`;
          csvContent += `Metric Type,Value
`;
          analytics.forEach((day) => {
            csvContent += `${day.metricType || "unknown"},${day.metricValue || 0}
`;
          });
          csvContent += "\n";
        }
        if (exportData.teams.length > 0) {
          csvContent += `## Team Performance
`;
          csvContent += `Team Name,Description,Active
`;
          exportData.teams.forEach((team) => {
            csvContent += `${team.teamName},${team.teamDescription},${team.isActive ? "Yes" : "No"}
`;
          });
          csvContent += "\n";
        }
        if (exportData.challenges.length > 0) {
          csvContent += `## Challenge Performance
`;
          csvContent += `Challenge Title,Description,Active
`;
          exportData.challenges.forEach((challenge) => {
            csvContent += `${challenge.title},${challenge.description},${challenge.isActive ? "Yes" : "No"}
`;
          });
        }
        res.setHeader("Content-Type", "text/csv");
        res.setHeader("Content-Disposition", `attachment; filename="${account.companyName.replace(/[^a-zA-Z0-9]/g, "_")}_wellness_report_${(/* @__PURE__ */ new Date()).toISOString().split("T")[0]}.csv"`);
        res.send(csvContent);
      } else {
        res.json(exportData);
      }
    } catch (error) {
      res.status(500).json({ message: error.message });
    }
  });
